#include<bits/stdc++.h>
using namespace std;
int p[2000010],d[2000010],d1[2000010],s[2000010];
bool flag[2000010];
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d",&p[i],&d[i]);
        p[i+n]=p[i];
        d[i+n]=d[i];
        d1[i]=d1[i+n]=d[i];
    }
    for(int i=1;i<=n*2;i++)
    {
        s[i]=s[i-1]-d[i]+p[i];
    }
    deque<int> q;
    for(int i=1;i<=n*2;i++)
    {
        while(!q.empty()&&s[q.back()]>=s[i])
        {
            q.pop_back();
        }
        q.push_back(i);
        while(!q.empty()&&q.front()<i-n+1)
        {
            q.pop_front();
        }
        if(i>=n&&s[q.front()]-s[i-n]>=0)
        {
            flag[i-n+1]=1;
        }
    }
    reverse(p+1,p+1+(n*2));
    reverse(d1+1,d1+1+(n*2));
    for(int i=1;i<=n;i++)
    {
        if(i==n)
        {
            d[i]=d1[1];
        }
        else
        {
            d[i]=d1[i+1];
        }
        d[i+n]=d[i];
    }
    memset(s,0,sizeof(s));
    for(int i=1;i<=n*2;i++)
    {
        s[i]=s[i-1]-d[i]+p[i];
    }
    q.clear();
    for(int i=1;i<=n*2;i++)
    {
        while(!q.empty()&&s[q.back()]>=s[i])
        {
            q.pop_back();
        }
        q.push_back(i);
        while(!q.empty()&&q.front()<i-n+1)
        {
            q.pop_front();
        }
        if(i>=n&&s[q.front()]-s[i-n]>=0)
        {
            flag[n-(i-n+1)+1]=1;
        }
    }
    for(int i=1;i<=n;i++)
    {
        if(flag[i])
        {
            printf("TAK\n");
        }
        else
        {
            printf("NIE\n");
        }
    }
    return 0;
}
